// // This module implements a 4-bit shift register with load capabilities. On each rising edge of the clock, if the reset signal is asserted, the output is cleared to zero. If the load signal is active, the register takes in a new 4-bit input value; otherwise, the current output shifts right by one bit, with a zero filling in the most significant bit.
module top_module(
    input clk, rst, load,
    input [3:0] in,
    output reg [3:0] out
);always @(posedge clk) begin
        if (rst) begin
            out <= 4'b0;
        end else if (load) begin
            out <= in;
        end else begin
            out <= {out[2:0], 1'b0};
        end
    end

endmodule
